class BaseWidget {
    static instanceCount: int = 0
    static totalScore: int = 0

    public id: string
    public cls: string
    protected score: int = 0
    protected active: bool = true
    private _dirty: bool = false

    constructor(id: string, cls: string, score: int) {
        this.id = id
        this.cls = cls
        this.score = score
        this._dirty = score < 0
        BaseWidget.instanceCount = BaseWidget.instanceCount + 1
        BaseWidget.totalScore = BaseWidget.totalScore + score
    }

    static getGlobalScore(): int {
        return BaseWidget.totalScore * BaseWidget.instanceCount - BaseWidget.instanceCount
    }

    isReady(): bool {
        return this.active && !this._dirty && this.score >= 0 && BaseWidget.instanceCount > 0
    }

    computeScore(factor: int): int {
        return this.score * factor - BaseWidget.totalScore / (BaseWidget.instanceCount + 1)
    }

    render(): string {
        return <div
            id={this.id}
            class={this.cls}
            data-score={this.score}
            data-ready={this.isReady()}
            data-global={BaseWidget.getGlobalScore()}
            data-flag={this.isReady() && this.score > 0 && !this._dirty}
        >
            <span data-val={this.score}>{this.score}</span>
        </div>
    }
}

class DataWidget extends BaseWidget {
    public values: int[]
    public labels: string[]
    protected threshold: int
    protected multiplier: int
    private _processed: bool = false
    static dataInstances: int = 0

    constructor(id: string, cls: string, values: int[], labels: string[], threshold: int, multiplier: int) {
        super(id, cls, values[0] * multiplier - threshold)
        this.values = values
        this.labels = labels
        this.threshold = threshold
        this.multiplier = multiplier
        DataWidget.dataInstances = DataWidget.dataInstances + 1
    }

    static getDataScore(): int {
        return DataWidget.dataInstances * BaseWidget.getGlobalScore() - BaseWidget.totalScore
    }

    processValues(): int {
        val total = 0
        val peak = 0
        val i = 0
        while (i < this.values.length) {
            val item = this.values[i] * this.multiplier - this.threshold
            if (item < 0 && !this._processed) {
                i = i + 1
                continue
            }
            if (item > peak) {
                peak = item
            }
            total = total + item
            if (total > this.threshold * this.multiplier * this.values.length) {
                break
            }
            i = i + 1
        }
        this._processed = true
        this.score = total - peak + this.computeScore(this.multiplier)
        BaseWidget.totalScore = BaseWidget.totalScore + this.score
        return total
    }

    getLabel(idx: int): string {
        return this.labels[idx]
    }

    render(): string {
        val total = this.processValues()
        val ready = this.isReady()
        val dataScore = DataWidget.getDataScore()
        return <section
            id={this.id}
            class={this.cls}
            data-total={total}
            data-score={this.score}
            data-threshold={this.threshold}
            data-ready={ready}
            data-global={BaseWidget.getGlobalScore()}
            data-data={dataScore}
            data-flag={ready && total > this.threshold && dataScore > 0 && !this._processed}
            data-chain={total * this.multiplier - this.threshold * DataWidget.dataInstances + BaseWidget.totalScore}
        >
            <header data-score={this.score} data-ready={ready}>
                <h2 data-val={total}>{this.labels[0]}: {total}</h2>
                <small data-flag={ready && total > 0}>
                    {this.score} / {this.threshold}
                </small>
            </header>
            <ul data-count={this.values.length} data-total={total}>
                <li data-val={this.values[0]} data-label={this.getLabel(0)}>
                    {this.labels[0]}: {this.values[0] * this.multiplier}
                </li>
                <li
                    data-val={this.values[this.values.length - 1]}
                    data-score={this.score}
                    data-flag={this.score > this.threshold && ready}
                >
                    {this.labels[this.labels.length - 1]}: {this.values[this.values.length - 1]}
                </li>
            </ul>
            <footer
                data-total={total}
                data-score={this.score}
                data-valid={ready && total > 0 && this.score > 0}
            >
                <span data-global={BaseWidget.getGlobalScore()} data-data={dataScore}>
                    Global: {BaseWidget.getGlobalScore()} · Data: {dataScore}
                </span>
            </footer>
        </section>
    }
}

class DashboardWidget extends DataWidget {
    public title: string
    public widgets: string[]
    private _collapsed: bool = false
    protected maxVisible: int
    static dashboardCount: int = 0

    constructor(id: string, cls: string, title: string, values: int[], labels: string[], maxVisible: int, threshold: int, multiplier: int) {
        super(id, cls, values, labels, threshold, multiplier)
        this.title = title
        this.maxVisible = maxVisible
        this._collapsed = values.length > maxVisible
        this.widgets = labels
        DashboardWidget.dashboardCount = DashboardWidget.dashboardCount + 1
        this.score = this.processValues() * multiplier - threshold * DashboardWidget.dashboardCount
    }

    static getDashboardScore(): int {
        return DashboardWidget.dashboardCount * DataWidget.getDataScore() - BaseWidget.getGlobalScore()
    }

    isCollapsed(): bool {
        return this._collapsed && this.values.length > this.maxVisible && this.isReady()
    }

    buildChildren(count: int): int {
        val built = 0
        val total = 0
        for (val i = 0; i < count && i < this.values.length; i = i + 1) {
            val child = new DataWidget(
                this.id,
                this.cls,
                this.values,
                this.labels,
                this.threshold * i + 1,
                this.multiplier
            )
            val childScore = child.processValues() * this.multiplier - child.computeScore(i + 1)
            if (childScore < 0 && !this.isReady()) {
                continue
            }
            total = total + childScore
            built = built + 1
            BaseWidget.totalScore = BaseWidget.totalScore + childScore
            if (built >= this.maxVisible) {
                break
            }
        }
        return total
    }

    render(): string {
        val total = this.processValues()
        val childTotal = this.buildChildren(this.maxVisible)
        val collapsed = this.isCollapsed()
        val globalScore = BaseWidget.getGlobalScore()
        val dataScore = DataWidget.getDataScore()
        val dashScore = DashboardWidget.getDashboardScore()
        val w0 = new DataWidget(this.id, this.cls, this.values, this.labels, this.threshold, this.multiplier)
        val w1 = new DataWidget(this.id, this.cls, this.values, this.labels, this.threshold * 2, this.multiplier + 1)

        return <div
            id={this.id}
            class={this.cls}
            data-title={this.title}
            data-total={total}
            data-child-total={childTotal}
            data-score={this.score}
            data-collapsed={collapsed}
            data-ready={this.isReady()}
            data-global={globalScore}
            data-data={dataScore}
            data-dash={dashScore}
            data-count={DashboardWidget.dashboardCount}
            data-flag={this.isReady() && !collapsed && total > this.threshold && childTotal > 0 && globalScore > dashScore}
            data-chain={total * this.multiplier - childTotal * this.threshold + dashScore * DashboardWidget.dashboardCount - BaseWidget.totalScore}
        >
            <header
                data-collapsed={collapsed}
                data-score={this.score}
                data-global={globalScore}
                data-ready={this.isReady()}
            >
                <h1 data-val={total}>{this.title}</h1>
                <span data-score={this.score} data-flag={this.score > 0 && !collapsed}>
                    Score: {this.score} / {this.threshold}
                </span>
                <small
                    data-global={globalScore}
                    data-data={dataScore}
                    data-dash={dashScore}
                    data-flag={globalScore > dataScore && dataScore > dashScore && !collapsed}
                >
                    G:{globalScore} D:{dataScore} Dash:{dashScore}
                </small>
            </header>
            <section
                data-count={this.values.length}
                data-visible={this.maxVisible}
                data-collapsed={collapsed}
                data-child-total={childTotal}
            >
                {w0.render()}
                {w1.render()}
            </section>
            <footer
                data-total={total}
                data-child={childTotal}
                data-score={this.score}
                data-valid={this.isReady() && total > 0 && childTotal > 0 && !collapsed}
                data-flag={this.score > this.threshold && globalScore > 0 && !this._collapsed && DashboardWidget.dashboardCount > 0}
            >
                <button
                    data-action="toggle"
                    data-collapsed={collapsed}
                    disabled={!this.isReady() || this.score < 0 || BaseWidget.instanceCount == 0}
                >
                    {collapsed && this.maxVisible} of {this.values.length} items
                </button>
                <span
                    data-instances={BaseWidget.instanceCount}
                    data-total={BaseWidget.totalScore}
                    data-flag={BaseWidget.instanceCount > 0 && BaseWidget.totalScore > 0 && !collapsed}
                >
                    Instances: {BaseWidget.instanceCount} · Total: {BaseWidget.totalScore}
                </span>
            </footer>
        </div>
    }
}

